import React, { useMemo, useState } from 'react';
import {
  Button,
  Input,
  Select,
  Modal,
  Checkbox,
  SearchInput,
  addToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { AccountChartMetaDto, AccountDto } from '../../../services/master/models';
import { createAccountSearchConfig, clearAccountSearchCache, formatAccountDisplay } from '../../../components/search';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import {
  CatalogFormFooter,
  CatalogListPagination,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
  SharedCatalogToolbarActions,
  SharedCatalogFormActions,
  SharedCatalogApprovalDrawer,
} from '../../../components/catalog';

import { buildSharedCatalogChangePayloadJson } from '../../../utils/sharedCatalogProposalPayload';
import type { SharedCatalogProposalSubmitChange } from '../../../components/catalog/SharedCatalogProposalModal';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-tai-khoan';

const SCOPE_FILTER_OPTIONS: { value: string; label: string }[] = [
  { value: '', label: 'Tất cả phạm vi' },
  { value: 'System', label: 'Dùng chung (thông tư)' },
  { value: 'Company', label: 'Riêng đơn vị' },
];

type FormErrors = Partial<Record<'code' | 'name', string>>;

const TaiKhoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<AccountDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<AccountDto | null>(null);
  const parentAccountSearchConfig = useMemo(
    () => createAccountSearchConfig({ mode: 'all' }),
    [],
  );
  const [form, setForm] = useState<Partial<AccountDto>>({ isActive: true, isDetail: false });
  const [parentAccountName, setParentAccountName] = useState('');
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [deleteCode, setDeleteCode] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);
  const [chartMeta, setChartMeta] = useState<AccountChartMetaDto | null>(null);
  const [scopeFilter, setScopeFilter] = useState('');
  const [requestingShared, setRequestingShared] = useState(false);
  const [approvalOpen, setApprovalOpen] = useState(false);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
    });
  };
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getAccountChartMeta()
        .then(meta => { if (!cancelled) setChartMeta(meta); })
        .catch(() => { /* optional meta */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getAccounts({
        search: search.trim() || undefined,
        page,
        pageSize,
        scope: scopeFilter ? (scopeFilter as 'System' | 'Company') : undefined,
      })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải tài khoản', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, scopeFilter, dispatch]);

  React.useEffect(() => {
    if (!modalOpen || !form.parentCode?.trim()) {
      if (!form.parentCode) setParentAccountName('');
      return;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getAccounts({ search: form.parentCode, page: 1, pageSize: 20 }).then(res => {
        if (!cancelled) {
          const a = res.items.find(x => x.code === form.parentCode);
          setParentAccountName(a?.name ?? '');
        }
      });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [modalOpen, form.parentCode]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã tài khoản';
    if (!form.name?.trim()) next.name = 'Nhập tên tài khoản';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ isActive: true, isDetail: false });
    setParentAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: AccountDto) => {
    if (row.isReadOnly) {
      setViewOnlyShared(true);
      setEditing(row);
      setForm({ ...row });
      setParentAccountName('');
      setErrors({});
      markClean();
      setModalOpen(true);
      return;
    }
    setViewOnlyShared(false);
    setEditing(row);
    setForm({ ...row });
    setParentAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateAccount(editing.code, {
          name: form.name,
          parentCode: form.parentCode || undefined,
          isDetail: form.isDetail,
          isActive: form.isActive,
          note: form.note,
        });
      } else {
        await masterService.createAccount({
          ...form,
          scope: 'Company',
        });
      }
      markClean();
      dispatch(addToast({
        message: editing ? 'Cập nhật tài khoản thành công' : 'Tạo tài khoản thành công',
        type: 'success',
      }));
      setModalOpen(false);
      clearAccountSearchCache();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (code: string) => {
    try {
      await masterService.deleteAccount(code);
      dispatch(addToast({ message: 'Xóa tài khoản thành công', type: 'success' }));
      setDeleteCode(null);
      clearAccountSearchCache();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  const handleRequestSharedUsage = async (note?: string) => {
    setRequestingShared(true);
    try {
      await masterService.requestSharedCatalogUsage('accounts', note);
      dispatch(addToast({ message: 'Đã gửi yêu cầu sử dụng danh mục chung', type: 'success' }));
      const meta = await masterService.getAccountChartMeta();
      setChartMeta(meta);
      refresh();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Gửi yêu cầu thất bại', type: 'error' }));
    } finally {
      setRequestingShared(false);
    }
  };

  const handleCreateChangeRequest = async (body: {
    catalogKind: string;
    action: 'Create' | 'Update' | 'Delete';
    entityKey: string;
    payloadJson?: string;
  }) => {
    await masterService.createSharedCatalogChangeRequest(body);
    const actionLabel = body.action === 'Create' ? 'đưa vào dùng chung' : body.action === 'Update' ? 'sửa' : 'xóa';
    dispatch(addToast({ message: `Đã gửi đề xuất ${actionLabel} — chờ duyệt`, type: 'success' }));
  };

  const handleSubmitProposalChange = async (
    entityKey: string,
    submit: SharedCatalogProposalSubmitChange,
  ) => {
    await handleCreateChangeRequest({
      catalogKind: 'accounts',
      action: submit.action,
      entityKey,
      payloadJson: buildSharedCatalogChangePayloadJson(submit),
    });
  };

  const sharedListMeta = chartMeta
    ? {
        usageStatus: chartMeta.sharedUsageStatus,
        canRequest: chartMeta.canRequestShared,
        canApprove: chartMeta.canApproveShared,
      }
    : null;

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-book" /> Danh mục tài khoản</h1>
          <p className={styles.subtitle}>
            Chứng từ và phát sinh luôn riêng từng đơn vị. Danh mục TK có thể <strong>dùng chung</strong>
            {chartMeta?.activeAccountingStandard ? ` (${chartMeta.activeAccountingStandard})` : ''} sau khi được duyệt — sửa shared qua <strong>đề xuất + approve</strong>.
          </p>
        </div>
        <div className={styles.headerActions}>
          <SharedCatalogToolbarActions
            testIdPrefix={TEST_ID}
            catalogKind="accounts"
            meta={sharedListMeta}
            requesting={requestingShared}
            onRequestUsage={handleRequestSharedUsage}
            onOpenApprovalQueue={() => setApprovalOpen(true)}
          />
          <Button variant="primary" onClick={openAdd} data-testid={`${TEST_ID}-add-btn`}>
            <i className="fas fa-plus" /> Thêm TK riêng đơn vị
          </Button>
        </div>
      </div>

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách tài khoản"
        showTableLoading={showTableLoading}
        footer={
          <div className={styles.catalogListFooterStack}>
            <CatalogListPagination
              testIdPrefix={TEST_ID}
              page={page}
              totalCount={totalCount}
              pageSize={pageSize}
              onPageChange={setPage}
              onPageSizeChange={setPageSize}
            />
          </div>
        }
        filters={
          <>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <Input
                placeholder="Tìm mã, tên, TK cha..."
                value={searchDraft}
                onChange={e => setSearchDraft(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
              />
            </div>
            <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} showSearch={true} />
            <div className={styles.field} data-testid={`${TEST_ID}-field-scope`}>
              <Select
                label="Phạm vi"
                value={scopeFilter}
                placeholder="Tất cả phạm vi"
                className={selectPlaceholderClass(scopeFilter)}
                onChange={e => {
                  setScopeFilter(e.target.value);
                  resetPage();
                }}
                options={SCOPE_FILTER_OPTIONS}
              />
            </div>
          </>
        }
      >
        {items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên</th>
                  <th>Phạm vi</th>
                  <CatalogCompanyTh />
                  <th>TK cha</th>
                  <th>Chi tiết</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.code}>
                    <td><code>{r.code}</code></td>
                    <td>{r.name}</td>
                    <td>
                      <span className={r.scope === 'Shared' || r.scope === 'System' ? styles.tagSuccess : styles.tagDefault}>
                        {r.scope === 'Shared' || r.scope === 'System' ? 'Dùng chung' : 'Đơn vị'}
                      </span>
                    </td>
                    <CatalogCompanyTd label={r.companyName} />
                    <td>{r.parentCode ?? '—'}</td>
                    <td>{r.isDetail ? 'Có' : 'Không'}</td>
                    <td>
                      <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                        {r.isActive ? 'Dùng' : 'Ngưng'}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      {r.isReadOnly ? (
                        <>
                          <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Xem">
                            <i className="fas fa-eye" />
                          </button>
                          {chartMeta?.canRequestShared && (
                            <button
                              type="button"
                              className={styles.actionBtn}
                              title="Đề xuất sửa"
                              onClick={async () => {
                                try {
                                  await masterService.createSharedCatalogChangeRequest({
                                    catalogKind: 'accounts',
                                    action: 'Update',
                                    entityKey: r.code,
                                    payloadJson: JSON.stringify({ name: r.name, note: 'Đề xuất từ danh mục TK' }),
                                  });
                                  dispatch(addToast({ message: 'Đã gửi đề xuất sửa — chờ duyệt', type: 'success' }));
                                } catch (err: unknown) {
                                  dispatch(addToast({ message: err instanceof Error ? err.message : 'Gửi đề xuất thất bại', type: 'error' }));
                                }
                              }}
                            >
                              <i className="fas fa-paper-plane" />
                            </button>
                          )}
                        </>
                      ) : (
                        <>
                          <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Sửa">
                            <i className="fas fa-edit" />
                          </button>
                          <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteCode(r.code)} title="Xóa">
                            <i className="fas fa-trash" />
                          </button>
                        </>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </CatalogListShell>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem tài khoản dùng chung' : editing ? 'Sửa tài khoản' : 'Thêm tài khoản'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã tài khoản *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên tài khoản *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-parentCode`}>
              <label className={styles.label}>TK cha</label>
              <SearchInput
                config={parentAccountSearchConfig}
                value={form.parentCode ?? ''}
                primaryDisplay={formatAccountDisplay(form.parentCode ?? '', parentAccountName)}
                disabled={viewOnlyShared}
                onChange={a => {
                  if (editing?.code && a.code === editing.code) {
                    dispatch(addToast({
                      message: 'Không thể chọn chính tài khoản làm TK cha',
                      type: 'error',
                    }));
                    return;
                  }
                  markDirty();
                  setForm(f => ({ ...f, parentCode: normalizeCode(a.code) }));
                  setParentAccountName(a.name);
                }}
                onClear={() => {
                  markDirty();
                  setForm(f => ({ ...f, parentCode: undefined }));
                  setParentAccountName('');
                }}
                showLabel={false}
                showSecondaryInput={false}
                placeholder="Mã hoặc tên TK..."
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-isDetail`}>
              <Checkbox
                label="Tài khoản chi tiết"
                checked={form.isDetail ?? false}
                disabled={viewOnlyShared}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, isDetail: e.target.checked }));
                }}
              />
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            catalogKind="accounts"
            usageActive={chartMeta?.sharedUsageStatus === 'Active'}
            canRequest={!!chartMeta?.canRequestShared}
            row={editing}
            currentValues={{
              name: form.name,
              isDetail: form.isDetail,
              isActive: form.isActive,
            }}
            onSubmitUsage={handleRequestSharedUsage}
            onSubmitChange={handleSubmitProposalChange}
          />
          {viewOnlyShared ? (
            <div className={styles.modalActions}>
              <Button variant="secondary" onClick={closeFormModal}>Đóng</Button>
            </div>
          ) : (
            <CatalogFormFooter
              companyName={editing?.companyName ?? sessionCompanyName}
              testIdPrefix={TEST_ID}
              checked={form.isActive ?? true}
              onActiveChange={c => {
                markDirty();
                setForm(f => ({ ...f, isActive: c }));
              }}
              onCancel={closeFormModal}
              onSave={handleSave}
              saving={saving}
            />
          )}
        </div>
      </Modal>

      <LeaveConfirmModal {...leaveConfirmModalProps} />

      <SharedCatalogApprovalDrawer
        testIdPrefix={TEST_ID}
        catalogKind="accounts"
        isOpen={approvalOpen}
        onClose={() => setApprovalOpen(false)}
        onReviewed={async () => {
          const meta = await masterService.getAccountChartMeta();
          setChartMeta(meta);
          refresh();
        }}
      />

      <Modal isOpen={!!deleteCode} onClose={() => setDeleteCode(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa tài khoản <code>{deleteCode}</code>?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteCode(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteCode && handleDelete(deleteCode)}>Xóa</Button>
        </div>
      </Modal>
    </div>
  );
};

export default TaiKhoanPage;
